{
  "domain_analysis": {
    "business_context": "Leave management module within an HR software system. Governs how employees accrue, request, consume, and carry over paid leave. The module enforces accrual-based entitlement, advance-notice requirements, manager approval workflows, and year-end carryover caps.",
    "bounded_context": "Leave Management",
    "ubiquitous_language": [
      { "term": "Leave Balance", "definition": "The number of accrued but unused leave days an employee currently holds. Must never go negative." },
      { "term": "Accrual", "definition": "The process by which an employee earns 1.5 days of leave per month worked. Accrual is tied to months of active employment." },
      { "term": "Leave Request", "definition": "A formal submission by an employee to consume accrued leave for a specified date range. Has a lifecycle: Pending → Approved/Rejected." },
      { "term": "Medical Leave", "definition": "A special category of leave that may be submitted retroactively (within 5 calendar days of the absence) provided a doctor's note is attached." },
      { "term": "Working Days", "definition": "Business days excluding weekends and company-recognized holidays. Used to calculate the 3-day advance notice requirement." },
      { "term": "Doctor's Note", "definition": "A medical certificate required as supporting evidence for retroactive medical leave requests." },
      { "term": "Contract End Date", "definition": "The date on which an employee's employment contract terminates. Leave requests must not span beyond this date." },
      { "term": "Carryover", "definition": "The transfer of unused leave balance from one calendar year to the next, capped at 10 days. Days above the cap are forfeited." },
      { "term": "Forfeiture", "definition": "The permanent loss of accrued leave days that exceed the 10-day carryover cap at calendar year-end." },
      { "term": "Advance Notice Period", "definition": "The minimum 3 working days between the date a leave request is submitted and the first day of requested leave." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "Employees accrue 1.5 days of leave per month worked.",
      "invariant": false,
      "invariant_justification": "The accrual rate of 1.5 days/month is a policy parameter that HR leadership could change (e.g., to 2.0 days for senior employees). It is not a data-integrity constraint.",
      "testable_assertion": "After completing N full months of employment, an employee's total accrued leave equals N × 1.5 days (before any consumption or forfeiture)."
    },
    {
      "id": "BR-2",
      "rule": "An employee's leave balance must never go negative. Leave cannot be taken before it is accrued.",
      "invariant": true,
      "invariant_justification": "A negative leave balance means the system has granted time off that was never earned — this is a state-integrity violation. The system would be in a corrupt state allowing consumption of a resource that does not exist.",
      "testable_assertion": "For any employee at any point in time: leave_balance >= 0. No leave request approval may reduce balance below zero."
    },
    {
      "id": "BR-3",
      "rule": "Non-medical leave requests must be submitted at least 3 working days before the first day of requested leave.",
      "invariant": false,
      "invariant_justification": "The 3-working-day notice period is a policy preference that management could relax (e.g., to 1 day for emergencies). It does not protect data integrity.",
      "testable_assertion": "A non-medical leave request submitted fewer than 3 working days before its start date is rejected at submission time."
    },
    {
      "id": "BR-4",
      "rule": "Medical leave may be submitted retroactively but must be submitted within 5 calendar days of the absence and must include a doctor's note.",
      "invariant": false,
      "invariant_justification": "The 5-day window and doctor's note requirement are policy decisions that could be adjusted. They do not protect system state integrity.",
      "testable_assertion": "A medical leave request for a past date is accepted only if (a) it is submitted within 5 calendar days of the absence date AND (b) a doctor's note is attached. Otherwise it is rejected."
    },
    {
      "id": "BR-5",
      "rule": "Only a manager may approve or reject a leave request.",
      "invariant": true,
      "invariant_justification": "Authorization control is a system integrity constraint. If non-managers could approve leave, the approval workflow is fundamentally broken and audit trails are meaningless.",
      "testable_assertion": "The approve/reject action on a leave request can only be performed by a user with the Manager role for the requesting employee."
    },
    {
      "id": "BR-6",
      "rule": "Rejected leave does not consume leave balance.",
      "invariant": true,
      "invariant_justification": "If a rejected request consumed balance, the system would be deducting entitlement for leave never taken — a data consistency corruption.",
      "testable_assertion": "When a leave request transitions to Rejected status, the employee's leave balance remains unchanged from its value before the request was submitted."
    },
    {
      "id": "BR-7",
      "rule": "A leave request must not span across (beyond) the employee's contract end date.",
      "invariant": true,
      "invariant_justification": "Granting leave beyond a contract end date means authorizing absence for a period when the person is no longer an employee. This is a logical integrity violation — the employment relationship that underpins leave entitlement does not exist.",
      "testable_assertion": "A leave request where the last day of leave > employee's contract end date is rejected at submission time."
    },
    {
      "id": "BR-8",
      "rule": "At calendar year-end, unused leave above 10 days is forfeited. Only up to 10 days carry over to the next year.",
      "invariant": false,
      "invariant_justification": "The 10-day carryover cap is a policy threshold that could be changed by HR leadership (e.g., increased to 15 during a pandemic). It does not protect data integrity.",
      "testable_assertion": "On January 1st of each year, if an employee's leave balance exceeded 10 days on December 31st, the new year balance is set to exactly 10 days. If balance was <= 10, it carries over in full."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An employee has worked 4 full months with no leave taken",
      "when": "The system calculates their leave balance",
      "then": "The balance is exactly 6.0 days (4 × 1.5)"
    },
    {
      "id": "AC-2",
      "given": "An employee has a leave balance of 2 days",
      "when": "They submit a leave request for 3 days",
      "then": "The request is rejected at submission with an insufficient-balance error"
    },
    {
      "id": "AC-3",
      "given": "An employee submits a non-medical leave request on a Monday",
      "when": "The requested leave start date is Wednesday of the same week (2 working days away)",
      "then": "The request is rejected for insufficient advance notice"
    },
    {
      "id": "AC-4",
      "given": "An employee submits a non-medical leave request on a Monday",
      "when": "The requested leave start date is Thursday of the same week (3 working days away) and sufficient balance exists",
      "then": "The request is accepted for manager review"
    },
    {
      "id": "AC-5",
      "given": "An employee was absent 3 calendar days ago due to illness",
      "when": "They submit a medical leave request with a valid doctor's note attached",
      "then": "The retroactive request is accepted for manager review"
    },
    {
      "id": "AC-6",
      "given": "An employee was absent 6 calendar days ago due to illness",
      "when": "They submit a medical leave request with a doctor's note",
      "then": "The request is rejected because it exceeds the 5-calendar-day retroactive window"
    },
    {
      "id": "AC-7",
      "given": "An employee submits a retroactive medical leave request within 5 days",
      "when": "No doctor's note is attached",
      "then": "The request is rejected for missing required documentation"
    },
    {
      "id": "AC-8",
      "given": "A leave request is in Pending status",
      "when": "The employee's manager rejects it",
      "then": "The request status becomes Rejected and the employee's leave balance is unchanged"
    },
    {
      "id": "AC-9",
      "given": "A leave request is in Pending status and the employee has sufficient balance",
      "when": "The employee's manager approves it",
      "then": "The request status becomes Approved and the employee's leave balance is reduced by the number of leave days"
    },
    {
      "id": "AC-10",
      "given": "An employee's contract ends on March 15",
      "when": "They submit a leave request for March 13–17",
      "then": "The request is rejected because it spans beyond the contract end date"
    },
    {
      "id": "AC-11",
      "given": "An employee has 14 unused leave days on December 31",
      "when": "The calendar year rolls over to January 1",
      "then": "Their leave balance is set to 10 days and 4 days are forfeited"
    },
    {
      "id": "AC-12",
      "given": "An employee has 8 unused leave days on December 31",
      "when": "The calendar year rolls over to January 1",
      "then": "Their leave balance remains 8 days — no forfeiture occurs"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Employee submits leave request on the exact contract end date (single-day request for the last day of contract)",
      "expected_behavior": "Should be accepted — the leave does not span beyond the contract end date, it ends on it. The request is valid assuming balance and notice requirements are met."
    },
    {
      "scenario": "Medical leave submitted on exactly the 5th calendar day after the absence",
      "expected_behavior": "Should be accepted — 'within 5 days' includes the 5th day (boundary inclusive). The spec says 'within 5 days,' so day 5 is the last valid submission day."
    },
    {
      "scenario": "Leave request submitted exactly 3 working days in advance",
      "expected_behavior": "Should be accepted — the rule says 'at least 3 working days,' so exactly 3 satisfies the requirement."
    },
    {
      "scenario": "Employee has exactly 0 days balance and submits a 0-day leave request",
      "expected_behavior": "A 0-day leave request is logically meaningless and should be rejected with a validation error. Leave requests must cover at least 1 day."
    },
    {
      "scenario": "Accrual for partial months worked (e.g., employee starts mid-month or contract ends mid-month)",
      "expected_behavior": "Spec says '1.5 days per month worked' but does not define partial-month accrual. This is an ambiguity — proration policy must be clarified."
    },
    {
      "scenario": "Leave balance is exactly 10 days on December 31",
      "expected_behavior": "No forfeiture occurs — the rule forfeits only the amount 'above 10 days.' Exactly 10 carries over in full."
    },
    {
      "scenario": "Manager tries to approve a leave request but the employee's balance has been consumed by a concurrent approval of another request",
      "expected_behavior": "The approval must be rejected or blocked because it would cause a negative balance. The non-negative balance invariant (BR-2) must hold even under concurrent approvals — balance check must occur at approval time, not only at submission time."
    },
    {
      "scenario": "A pending leave request exists when the employee's contract end date is shortened",
      "expected_behavior": "If the pending request now spans beyond the new contract end date, it should be automatically invalidated or flagged for re-review. BR-7 must hold at approval time."
    },
    {
      "scenario": "Employee submits non-medical leave for a date that is 3 working days away, but a company holiday falls within those 3 days",
      "expected_behavior": "Company holidays are not working days. The advance notice calculation must exclude holidays, which may cause the request to fail the 3-working-day requirement."
    },
    {
      "scenario": "Medical leave request submitted retroactively for a date that falls in the previous calendar year (cross-year boundary)",
      "expected_behavior": "The 5-day retroactive window still applies. However, the balance deduction should come from the year in which the absence occurred, which may interact with the carryover/forfeiture calculation."
    }
  ],

  "business_impact": {
    "financial": "Incorrect accrual or carryover logic directly affects the company's leave liability on the balance sheet. Over-accrual inflates liabilities; failure to forfeit excess days creates hidden financial exposure. Negative balances represent unearned compensation paid out.",
    "operational": "The 3-working-day advance notice requirement enables workforce planning — managers need lead time to arrange coverage. Retroactive medical leave with documentation balances employee welfare against abuse prevention. The carryover cap incentivizes employees to use leave, reducing end-of-year staffing crunches.",
    "user": "Employees need a clear, predictable system: they must see their accurate balance, understand why requests are accepted or rejected, and trust the system handles year-end carryover correctly. Confusing rejections or surprise forfeitures erode trust.",
    "risk": "Non-negative balance invariant violations create payroll and audit risks. Missing doctor's note enforcement opens the door to retroactive leave abuse. Failing to enforce contract-end-date boundaries could create legal exposure for granting benefits to non-employees.",
    "stakeholders_affected": [
      { "group": "Employees", "impact": "Direct users who accrue and consume leave. Incorrect balances or opaque rejection reasons degrade their experience and trust." },
      { "group": "Managers", "impact": "Responsible for approving/rejecting leave. Need accurate balance information and timely requests to plan team capacity." },
      { "group": "HR Department", "impact": "Owns leave policy compliance, handles disputes, and audits balances. Depends on correct carryover and accrual logic for reporting." },
      { "group": "Finance/Payroll", "impact": "Leave liability directly affects balance sheet provisioning. Incorrect balances lead to misreported financials." },
      { "group": "Legal/Compliance", "impact": "Leave beyond contract end dates or missing medical documentation creates compliance risk. Labor law adherence depends on correct enforcement." }
    ]
  },

  "confidence": {
    "level": 72,
    "reasoning": "The spec is well-structured and internally consistent with no contradictions. However, several operational details are left unspecified: partial-month accrual rules, the definition of 'working days' (which holidays count), when exactly balance is deducted (submission vs approval), and how pending requests interact with year-end forfeiture. These gaps are common in early specs but affect implementation correctness.",
    "high_confidence_areas": [
      "Non-negative balance invariant — unambiguously stated",
      "Accrual rate for full months — clearly 1.5 days/month",
      "Carryover cap of 10 days with forfeiture — clearly defined",
      "Medical leave retroactive exception with doctor's note within 5 days — clear",
      "Rejected leave does not consume balance — explicit",
      "Leave cannot span past contract end date — explicit"
    ],
    "low_confidence_areas": [
      "Partial-month accrual (start/end mid-month) — not specified",
      "Definition of 'working days' and which holidays are recognized — not specified",
      "When balance is deducted: at submission (reserved) vs at approval — not specified",
      "How pending requests interact with year-end forfeiture — not specified",
      "Whether the '5 days' for medical leave is calendar days or working days — assumed calendar based on wording",
      "Whether half-day leave requests are permitted — not specified"
    ],
    "assumptions": [
      "The 5-day retroactive window for medical leave is measured in calendar days, not working days",
      "Balance deduction occurs at approval time, not at submission time, since rejected leave does not consume balance",
      "The 3-working-day notice is calculated from the day after submission to the day before the leave start date",
      "'Month worked' means a full calendar month of active employment",
      "Carryover forfeiture runs as a batch process on December 31 / January 1 boundary"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Partial-month accrual is undefined. If an employee starts on the 15th of a month, do they accrue a prorated 0.75 days, the full 1.5 days, or nothing until a full month is completed?",
      "affected_stakeholders": ["Employees", "HR Department", "Finance/Payroll"],
      "options": [
        "Prorate based on calendar days worked in the month",
        "Require a full calendar month before any accrual",
        "Accrue for any month in which at least 15 days are worked"
      ],
      "recommendation": "Prorate based on calendar days worked — it is the most equitable and standard approach in HR systems."
    },
    {
      "type": "ambiguity",
      "description": "Balance deduction timing is not specified. Is balance reserved (held) at submission time, or deducted only upon manager approval? This affects concurrent request handling.",
      "affected_stakeholders": ["Employees", "Managers"],
      "options": [
        "Reserve balance at submission, release if rejected",
        "Deduct only at approval, validate balance at both submission and approval"
      ],
      "recommendation": "Reserve at submission and release on rejection — prevents double-booking of leave balance from concurrent requests and gives employees immediate feedback on available balance."
    },
    {
      "type": "ambiguity",
      "description": "The definition of 'working days' is not specified — which holidays are excluded? This affects the 3-day advance notice calculation.",
      "affected_stakeholders": ["Employees", "Managers", "HR Department"],
      "options": [
        "Use a company holiday calendar maintained by HR",
        "Use only weekends (Sat/Sun) as non-working days",
        "Use locale-specific public holidays"
      ],
      "recommendation": "Use a company-maintained holiday calendar — it is the most accurate and gives HR control over what counts as a working day."
    }
  ],

  "rejection_reasons": []
}

